SELECT rv.recipe_video_id, rv.video_title, rv.thumbnail_url, rv.video_url, rv.view_count, rv.user_view_count, rv.duration, i.item_id, i.item_name FROM recipe_video rv LEFT JOIN recipe_items ri ON rv.recipe_video_id = ri.recipe_video_id LEFT JOIN items i ON ri.item_id = i.item_id WHERE rv.recipe_video_id IN
#{recipeVideoId}
ORDER BY FIELD( rv.recipe_video_id,
#{recipeVideoId}
)

SELECT EXISTS (
    SELECT 1
    FROM liked_recipe
    WHERE recipe_video_id = #{recipeVideoId}
      AND user_id = #{userId}
)

SELECT EXISTS (
    SELECT 1
    FROM completed_recipe
    WHERE recipe_video_id = #{recipeVideoId}
      AND user_id = #{userId}
)

SELECT COUNT(*)
FROM completed_recipe
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM liked_recipe
WHERE user_id = #{userId}

